mapper.select:
/* com.shop.mapper.frontWeb.display.selectProductInfoListForEnumPaging */ SELECT TPD.ID AS prodDetId , TPD.PRODUCT_DET_COLOR AS prodDetColor , TP.ID AS prodId , TP.PROD_NM AS prodNm , TP.SELL_AMT AS sellAmt FROM TB_RPODUCT_DET TPD JOIN TB_PRODUCT TP ON TP.ID = TPD.PRODUCT_ID AND TP.DEL_YN = 'N'
AND TPD.DEL_YN = 'N' AND TPD.IS_REP = true
AND (TPD.ID) >= (#{filter.lastProdDetId})
ORDER BY TP.ID LIMIT #{pageRowCount} + 1;
